INSERT INTO document_templates (template_id, name, doc_type, template_version, status, template_content, effective_from, published_at) VALUES
('01_seller_landlord_authorization', 'Seller / Landlord Authorization (Form A Equivalent)', 'Mandate', 'v1.0', 'Published', E'Seller / Landlord Authorization (Form A Equivalent)\n\nPurpose\nThis authorization appoints MiCasa Real Estate LLC to market and negotiate the sale and/or lease of the described property in Abu Dhabi, and records the parties'' responsibilities and commission terms.\n\n1. Parties\nThis authorization is made between the following parties:\n\nPrincipal (Seller / Landlord)\nFull Name: ______________________________________________\nEmirates ID / Passport No.: ______________________________\nAddress: _______________________________________________\nMobile: ________________________________________________\nEmail: _________________________________________________\n\nBroker\nCompany: MiCasa Real Estate LLC\nLicense No.: CN-3762725\nTRN: _________________________________________________\nAddress: _______________________________________________\nRepresentative: _________________________________________\nMobile: ________________________________________________\nEmail: _________________________________________________\n\n2. Property Details\nProperty Type: __________________________________________\nEmirate: Abu Dhabi\nCommunity / Building: ___________________________________\nUnit / Plot No.: ________________________________________\nTitle Deed / Tawtheeq No.: _______________________________\nApprox. Area (sq. ft./sq. m): ____________________________\nCurrent Status: _________________________________________\n\n3. Scope of Authority\nThe Principal authorizes the Broker to market, advertise, and negotiate the sale and/or lease of the Property on the Principal''s behalf, including arranging viewings, collecting offers, and coordinating with relevant authorities for transaction completion.\n\nTransaction Type (select one or both):\nSale: [  ] Yes  [  ] No\nLease: [  ] Yes  [  ] No\n\nAuthority Type: [  ] Exclusive  [  ] Non-Exclusive\n\n4. Term\nStart Date: __________________________\nEnd Date: ____________________________\nThis authorization remains valid for the above term unless terminated earlier by written notice in accordance with Section 11.\n\n5. Listing Price / Rental Terms\nSale Price (AED): _________________________________\nLease Terms (AED per annum / period): __________________\nThe Principal confirms that any change to price or rental terms must be approved in writing.\n\n6. Broker Duties\nThe Broker shall perform the following duties with reasonable skill and care:\n(a) Market and promote the Property using approved channels.\n(b) Verify prospective buyers/tenants for basic eligibility and capability.\n(c) Present offers and material communications to the Principal promptly.\n(d) Coordinate documentation and authority requirements for completion.\n\n7. Principal Duties\nThe Principal shall:\n(a) Provide accurate and complete information and documentation.\n(b) Allow reasonable access for viewings with notice.\n(c) Refrain from directly negotiating with parties introduced by the Broker during the term and for 12 months after termination.\n(d) Pay commission in accordance with Section 8.\n\n8. Commission\nCommission Rate: ________ % of transaction value, or\nFixed Commission Amount (AED): ________________________\nCommission Payable By: [  ] Principal  [  ] Other party as permitted by law\nCommission becomes due upon successful transfer (sale) or execution of a registered tenancy contract (lease), as applicable.\n\n9. Marketing Consent\nThe Principal authorizes the Broker to use photographs, floorplans, videos, and relevant property information for marketing, subject to applicable laws and any written restrictions stated below:\nRestrictions: _______________________________________________________________\n\n10. Compliance and Regulatory Requirements\nThe parties acknowledge that all activities must comply with Abu Dhabi DMT/ADM regulations and applicable UAE laws. The Principal shall provide any required approvals, NOCs, or documentation for lawful marketing and transaction completion.\n\n11. Termination\nEither party may terminate this authorization with written notice of ______ days. Termination does not affect the Broker''s right to commission for transactions concluded with parties introduced during the term or within the non-circumvention period.\n\n12. Governing Law\nThis authorization is governed by the laws of the United Arab Emirates and applicable regulations in the Emirate of Abu Dhabi.\n\n13. Entire Agreement\nThis authorization constitutes the entire agreement between the parties regarding the subject matter and supersedes prior discussions or understandings.\n\nSignatures\n\nPrincipal (Seller / Landlord)\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nBroker Representative (MiCasa Real Estate LLC)\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompany Stamp\n[Stamp Here]', now(), now()),

('02_buyer_tenant_representation_agreement', 'Buyer / Tenant Representation Agreement', 'Mandate', 'v1.0', 'Published', E'Buyer / Tenant Representation Agreement\n\nPurpose\nThis agreement appoints MiCasa Real Estate LLC to represent the Buyer and/or Tenant in locating and negotiating the purchase or lease of property in Abu Dhabi.\n\n1. Parties\nClient (Buyer / Tenant)\nFull Name: ______________________________________________\nEmirates ID / Passport No.: ______________________________\nAddress: _______________________________________________\nMobile: ________________________________________________\nEmail: _________________________________________________\n\nBroker\nCompany: MiCasa Real Estate LLC\nLicense No.: CN-3762725\nTRN: _________________________________________________\nAddress: _______________________________________________\nRepresentative: _________________________________________\nMobile: ________________________________________________\nEmail: _________________________________________________\n\n2. Representation Type\nThis agreement applies to (select one):\n[  ] Buyer representation (purchase)\n[  ] Tenant representation (lease)\n\n3. Scope of Services\nThe Broker shall:\n(a) Identify properties meeting the Client''s criteria.\n(b) Arrange viewings and provide market guidance.\n(c) Prepare and present offers or expressions of interest.\n(d) Coordinate negotiation and documentation to completion.\n\n4. Client Requirements\nPreferred Areas: ________________________________________\nProperty Type: _________________________________________\nBudget / Rent Range: ____________________________________\nMove-in / Completion Timeline: __________________________\n\n5. Exclusivity\n[  ] Exclusive representation for the term stated below.\n[  ] Non-exclusive representation.\n\n6. Term\nStart Date: __________________________\nEnd Date: ____________________________\nThis agreement terminates automatically at the end date unless renewed in writing.\n\n7. Commission and Fees\nCommission Rate: ________ % of purchase price or annual rent, or\nFixed Amount (AED): _________________________________\nCommission Payable By: [  ] Client  [  ] Seller/Landlord  [  ] Other as permitted by law\nCommission is due upon successful transfer (sale) or execution of a registered tenancy contract (lease), as applicable.\n\n8. Client Obligations\nThe Client shall:\n(a) Provide accurate personal and financial information.\n(b) Disclose any direct negotiations with owners or other agents.\n(c) Inform the Broker promptly of any accepted offer or lease execution.\n(d) Pay agreed commission in accordance with Section 7.\n\n9. Non-Circumvention\nThe Client shall not directly negotiate with any property or party introduced by the Broker during the term and for 12 months after termination without the Broker''s written consent.\n\n10. Confidentiality\nAll non-public information exchanged under this agreement shall be treated as confidential and used only for the transaction purpose.\n\n11. Governing Law\nThis agreement is governed by the laws of the United Arab Emirates and applicable regulations in the Emirate of Abu Dhabi.\n\n12. Entire Agreement\nThis agreement constitutes the entire agreement between the parties concerning representation services and supersedes prior discussions or arrangements.\n\nSignatures\n\nClient (Buyer / Tenant)\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nBroker Representative (MiCasa Real Estate LLC)\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompany Stamp\n[Stamp Here]', now(), now()),

('03_property_listing_authorization_marketing_consent', 'Property Listing Authorization & Marketing Consent', 'Mandate', 'v1.0', 'Published', E'Property Listing Authorization & Marketing Consent\n\nPurpose\nThis document authorizes MiCasa Real Estate LLC to list, advertise, and market the Property and records the Owner''s consent for media, portals, and price approvals.\n\n1. Parties\nOwner / Landlord\nFull Name: ______________________________________________\nEmirates ID / Passport No.: ______________________________\nAddress: _______________________________________________\nMobile: ________________________________________________\nEmail: _________________________________________________\n\nBroker\nCompany: MiCasa Real Estate LLC\nLicense No.: CN-3762725\nTRN: _________________________________________________\nRepresentative: _________________________________________\nMobile: ________________________________________________\nEmail: _________________________________________________\n\n2. Property Details\nProperty Type: __________________________________________\nCommunity / Building: ___________________________________\nUnit / Plot No.: ________________________________________\nTitle Deed / Tawtheeq No.: _______________________________\nFurnishing: _____________________________________________\nKey Access Contact: _____________________________________\n\n3. Listing Authorization\nThe Owner authorizes the Broker to list the Property for sale and/or lease and to display listing information to the public through approved channels.\n\nListing Type: [  ] Sale  [  ] Lease\nListed Price / Rent (AED): ______________________________\nPrice Validity Period: _________________________________\n\n4. Marketing Channels Consent\nThe Owner approves the Broker to use the following channels for marketing:\n(a) Property portals and listing aggregators.\n(b) Company website and CRM distribution.\n(c) Social media, SMS, email campaigns, and print materials.\n(d) Broker network and cooperating agents.\n\n5. Media and Photography Consent\nThe Owner consents to:\n(a) Professional photography, videography, and floorplan production.\n(b) Use of images and media in marketing materials and portal listings.\n(c) Reasonable editing for presentation, without altering material facts.\n\n6. Access and Viewing Arrangements\nThe Owner shall provide reasonable access for viewings on prior notice and shall ensure the Property is safe and accessible for prospective buyers/tenants.\n\n7. Accuracy of Information\nThe Owner confirms that all information provided is accurate and complete, including property size, condition, ownership, and any encumbrances.\n\n8. Price Changes and Withdrawal\nAny change in price or withdrawal of the listing requires written confirmation from the Owner. The Owner remains responsible for any costs incurred for marketing or media production unless otherwise agreed.\n\n9. Governing Law\nThis authorization is governed by the laws of the United Arab Emirates and applicable regulations in the Emirate of Abu Dhabi.\n\n10. Entire Agreement\nThis authorization constitutes the entire agreement regarding listing and marketing consent for the Property.\n\nSignatures\n\nOwner / Landlord\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nBroker Representative (MiCasa Real Estate LLC)\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompany Stamp\n[Stamp Here]', now(), now()),

('04_agent_license_registration_record', 'Agent License & Registration Record', 'Other', 'v1.0', 'Published', E'Agent License & Registration Record\n\nPurpose\nThis internal record documents the licensing and registration status of a MiCasa Real Estate LLC agent in accordance with Abu Dhabi DMT/ADM requirements and company compliance controls.\n\n1. Agent Identification\nFull Name: ______________________________________________\nEmployee / Contractor ID: ________________________________\nNationality: ____________________________________________\nEmirates ID No.: _________________________________________\nMobile: ________________________________________________\nEmail: _________________________________________________\n\n2. Licensing and Registration\nBroker Card / License No.: _______________________________\nIssuing Authority: ______________________________________\nIssue Date: _____________________________________________\nExpiry Date: ____________________________________________\nDMT / ADM Registration ID (if applicable): ________________\nRegistration Status: ____________________________________\n\n3. Training and Compliance\nMandatory Training Completed: ____________________________\nAML/KYC Training Date: _________________________________\nPDPL Awareness Training Date: ____________________________\nFit and Proper Declaration Date: _________________________\n\n4. Employment and Supervision\nSupervisor Name: ________________________________________\nSupervisor License No.: _________________________________\nOffice Location: ________________________________________\nRole / Specialization: __________________________________\n\n5. Supporting Documents on File\nDocuments held by Compliance:\n- Emirates ID copy\n- Passport and visa copy\n- Broker card copy\n- Training certificates\n- Signed code of conduct\n\n6. Notes and Exceptions\n__________________________________________________________________\n__________________________________________________________________\n\n7. Governing Law\nThis internal record is maintained in accordance with the laws of the United Arab Emirates and applicable regulations in the Emirate of Abu Dhabi.\n\nSignatures\n\nCompliance Officer\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nAgent Acknowledgment\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompany Stamp\n[Stamp Here]', now(), now()),

('05_company_trade_license_regulatory_record', 'Company Trade License & Regulatory Registration Record', 'Other', 'v1.0', 'Published', E'Company Trade License & Regulatory Registration Record\n\nPurpose\nThis internal master record consolidates MiCasa Real Estate LLC licensing, regulatory registrations, and key compliance identifiers for audit and operational reference.\n\n1. Company Identification\nLegal Name: MiCasa Real Estate LLC\nTrade Name: MiCasa Real Estate\nCompany Registration No. (CN): 3762725\nTrade License No.: ______________________________\nIssuing Authority: ______________________________\nTrade License Issue Date: ________________________\nTrade License Expiry Date: _______________________\nOffice Address: __________________________________\nTelephone: ______________________________________\nEmail: __________________________________________\n\n2. Regulatory Registrations\nAbu Dhabi DMT / ADM Registration No.: ____________\nActivities Registered: ___________________________\nRegistration Status: ____________________________\nRenewal Date: ___________________________________\n\n3. Tax Registration\nTRN (UAE VAT): __________________________________\nTax Registration Date: ___________________________\nVAT Filing Cycle: ________________________________\nFTA Portal Username (internal): ___________________\n\n4. Banking and Financial Controls\nPrimary Bank: ____________________________________\nAccount Name: ___________________________________\nAccount Number / IBAN: ___________________________\nAuthorized Signatories: __________________________\n\n5. Compliance Contacts\nCompliance Officer: ______________________________\nFinance Lead: ____________________________________\nData Protection Contact: __________________________\n\n6. Supporting Documents on File\nDocuments held by Compliance:\n- Trade license copy\n- DMT/ADM registration certificate\n- VAT registration certificate\n- Office lease/tenancy contract\n- Professional indemnity (if applicable)\n\n7. Notes and Exceptions\n__________________________________________________________________\n__________________________________________________________________\n\n8. Governing Law\nThis internal record is maintained in accordance with the laws of the United Arab Emirates and applicable regulations in the Emirate of Abu Dhabi.\n\nSignatures\n\nAuthorized Signatory\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompliance Officer\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompany Stamp\n[Stamp Here]', now(), now()),

('06_agent_to_agent_agency_agreement', 'Agent-to-Agent / Agency-to-Agency Agreement', 'ICA', 'v1.0', 'Published', E'Agent-to-Agent / Agency-to-Agency Agreement\n\nPurpose\nThis agreement sets the terms for cooperation between MiCasa Real Estate LLC and another licensed broker or agency for a specific transaction or ongoing cooperation, including commission sharing, non-circumvention, and confidentiality.\n\n1. Parties\nMiCasa Real Estate LLC\nLicense No.: CN-3762725\nTRN: _________________________________________________\nRepresentative: _________________________________________\nEmail: _________________________________________________\n\nCooperating Broker / Agency\nLegal Name: ____________________________________________\nLicense No.: ___________________________________________\nTRN (if applicable): ____________________________________\nRepresentative: _________________________________________\nEmail: _________________________________________________\n\n2. Scope of Cooperation\nThis agreement applies to the following:\n[  ] Specific Property/Deal\n[  ] Ongoing cooperation for multiple listings\n\nProperty / Deal Reference (if applicable): ________________\nClient Type Introduced: [  ] Buyer  [  ] Seller  [  ] Tenant  [  ] Landlord\n\n3. Commission Sharing\nTotal Commission: __________________________ (AED or %)\nMiCasa Share: _______________________________ (AED or %)\nCooperating Broker Share: _____________________ (AED or %)\nPayment Trigger: ______________________________\nPayment Method and Timing: ____________________\n\n4. Roles and Responsibilities\nEach party shall provide accurate information, comply with applicable laws, and act in good faith. Neither party shall make representations outside its authority or use the other party''s brand without written consent.\n\n5. Non-Circumvention\nEach party agrees not to bypass the other or directly solicit the other''s introduced clients for the subject transaction or any related transaction for a period of 12 months from the date of introduction.\n\n6. Confidentiality\nAll confidential information, client details, and deal terms exchanged shall be kept strictly confidential and used only for the stated purpose.\n\n7. Compliance\nEach party warrants that it is duly licensed and authorized in its jurisdiction and will comply with Abu Dhabi DMT/ADM regulations and applicable UAE laws.\n\n8. Governing Law\nThis agreement is governed by the laws of the United Arab Emirates and applicable regulations in the Emirate of Abu Dhabi.\n\n9. Entire Agreement\nThis agreement constitutes the entire agreement between the parties relating to the cooperation described herein.\n\nSignatures\n\nMiCasa Real Estate LLC\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCooperating Broker / Agency\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompany Stamp\n[Stamp Here]', now(), now()),

('07_offer_letter_expression_of_interest', 'Offer Letter / Expression of Interest', 'Other', 'v1.0', 'Published', E'Offer Letter / Expression of Interest\n\nPurpose\nThis letter records the Buyer''s or Tenant''s intent to proceed on specified commercial terms for the referenced property, subject to contract and authority approvals.\n\n1. Parties\nBuyer / Tenant\nFull Name: ______________________________________________\nEmirates ID / Passport No.: ______________________________\nMobile: ________________________________________________\nEmail: _________________________________________________\n\nSeller / Landlord\nFull Name: ______________________________________________\nContact: _______________________________________________\n\nBroker\nCompany: MiCasa Real Estate LLC\nRepresentative: _________________________________________\n\n2. Property Details\nProperty Address: _______________________________________\nUnit / Plot No.: ________________________________________\nTitle Deed / Tawtheeq No.: _______________________________\nProperty Type: __________________________________________\n\n3. Offer Terms\nOffer Price / Rent (AED): ________________________________\nPayment Terms: __________________________________________\nDeposit Amount (AED): ___________________________________\nProposed Transfer / Lease Start Date: ____________________\nFixtures and Inclusions: ________________________________\n\n4. Conditions\nThis offer is subject to:\n(a) Verification of title, authority, and property particulars.\n(b) Satisfactory inspection and due diligence.\n(c) Any required NOCs and authority approvals.\n(d) Execution of formal agreement(s) and registration.\n\n5. Validity\nThis offer is valid until __________________________ (date/time). If not accepted in writing by that time, it will lapse without liability.\n\n6. Non-Binding Nature\nThis letter expresses intent only and does not create a binding contract for sale or lease until formal agreements are executed by the parties.\n\n7. Governing Law\nThis letter is governed by the laws of the United Arab Emirates and applicable regulations in the Emirate of Abu Dhabi.\n\nSignatures\n\nBuyer / Tenant\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nSeller / Landlord (Acceptance)\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nBroker Acknowledgment (MiCasa Real Estate LLC)\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompany Stamp\n[Stamp Here]', now(), now()),

('08_memorandum_of_understanding_pre_spa', 'Memorandum of Understanding (MOU / SPA Pre-Stage)', 'MOU', 'v1.0', 'Published', E'Memorandum of Understanding (MOU / SPA Pre-Stage)\n\nPurpose\nThis MOU records the agreed sale terms prior to transfer and sets out the parties'' obligations pending execution of the final sale and transfer documentation.\n\n1. Parties\nSeller\nFull Name: ______________________________________________\nEmirates ID / Passport No.: ______________________________\nAddress: _______________________________________________\n\nBuyer\nFull Name: ______________________________________________\nEmirates ID / Passport No.: ______________________________\nAddress: _______________________________________________\n\nBroker\nCompany: MiCasa Real Estate LLC\nRepresentative: _________________________________________\n\n2. Property Details\nProperty Address: _______________________________________\nUnit / Plot No.: ________________________________________\nTitle Deed No.: _________________________________________\nProperty Type: __________________________________________\n\n3. Purchase Price and Payment\nTotal Purchase Price (AED): _____________________________\nDeposit Amount (AED): ___________________________________\nBalance Payment Method: _________________________________\nTarget Transfer Date: ___________________________________\n\n4. Deposit Handling\nThe deposit shall be held as follows: _____________________\nIf the Buyer defaults without lawful excuse, the deposit may be forfeited to the Seller subject to applicable law. If the Seller defaults, the deposit shall be returned to the Buyer.\n\n5. Seller Obligations\nThe Seller shall provide clear title and all required documents, cooperate with authority requirements, and sign transfer documents at the scheduled transfer date.\n\n6. Buyer Obligations\nThe Buyer shall complete due diligence promptly, secure funds, and attend the transfer appointment with all required documentation.\n\n7. Conditions Precedent\nThis MOU is subject to:\n(a) Verification of title and ownership.\n(b) Obtaining required NOCs and authority approvals.\n(c) Settlement of any outstanding service charges or liabilities.\n\n8. Default and Remedies\nIf either party fails to perform, the non-defaulting party may seek remedies available under applicable law, including specific performance or damages.\n\n9. Broker Role and Commission\nThe Broker facilitated the introduction and negotiation of the transaction. Commission is due upon successful transfer in accordance with the applicable brokerage agreements.\n\n10. Governing Law\nThis MOU is governed by the laws of the United Arab Emirates and applicable regulations in the Emirate of Abu Dhabi.\n\n11. Entire Agreement\nThis MOU constitutes the entire agreement between the parties regarding the pre-transfer terms and supersedes prior communications relating to the subject matter.\n\nSignatures\n\nSeller\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nBuyer\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nBroker Acknowledgment (MiCasa Real Estate LLC)\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompany Stamp\n[Stamp Here]', now(), now()),

('09_reservation_booking_form', 'Reservation / Booking Form', 'Reservation', 'v1.0', 'Published', E'Reservation / Booking Form\n\nPurpose\nThis form records a temporary reservation of the Property, the booking fee/deposit received, and the conditions for refund or forfeiture.\n\n1. Parties\nReserving Party (Buyer / Tenant)\nFull Name: ______________________________________________\nEmirates ID / Passport No.: ______________________________\nMobile: ________________________________________________\nEmail: _________________________________________________\n\nOwner / Landlord\nFull Name: ______________________________________________\nContact: _______________________________________________\n\nBroker\nCompany: MiCasa Real Estate LLC\nRepresentative: _________________________________________\n\n2. Property Details\nProperty Address: _______________________________________\nUnit / Plot No.: ________________________________________\nProperty Type: __________________________________________\n\n3. Reservation Terms\nReservation Start Date: _________________________________\nReservation End Date: ___________________________________\nReservation Fee / Booking Deposit (AED): _________________\nPayment Method: _________________________________________\n\n4. Purpose of Reservation\nThe reservation is intended to allow the parties to complete due diligence and execute the applicable sale or lease agreement within the reservation period.\n\n5. Refund and Forfeiture Terms\nThe reservation fee shall be:\n(a) Refunded to the Reserving Party if the Owner fails to proceed for reasons within the Owner''s control.\n(b) Applied to the purchase price or rental obligations upon successful execution of the agreement.\n(c) Forfeited if the Reserving Party withdraws without lawful excuse after acceptance, subject to applicable law.\n\n6. Documentation and Approvals\nThe parties shall cooperate to provide required documents, approvals, and NOCs during the reservation period.\n\n7. Governing Law\nThis reservation is governed by the laws of the United Arab Emirates and applicable regulations in the Emirate of Abu Dhabi.\n\n8. Entire Agreement\nThis reservation form constitutes the entire agreement for the reservation arrangement and supersedes prior discussions on the same subject.\n\nSignatures\n\nReserving Party\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nOwner / Landlord\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nBroker Acknowledgment (MiCasa Real Estate LLC)\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompany Stamp\n[Stamp Here]', now(), now()),

('10_deal_completion_closing_checklist', 'Deal Completion & Closing Checklist', 'Other', 'v1.0', 'Published', E'Deal Completion & Closing Checklist\n\nPurpose\nThis checklist confirms that all required steps and documents for the transaction have been completed and that the deal is ready for closure and audit filing.\n\n1. Transaction Summary\nDeal Reference: __________________________________________\nTransaction Type: [  ] Sale  [  ] Lease\nProperty Address: _______________________________________\nParties: ________________________________________________\nScheduled Completion Date: ______________________________\n\n2. Completion Checklist\nEach item below is confirmed as completed or attached:\n\nItem | Confirmation | Notes\n--- | --- | ---\nSigned MOU / Agreement | [  ] Yes [  ] No | ______________________________\nID and Authority Verified (all parties) | [  ] Yes [  ] No | ______________________________\nTitle Deed / Tawtheeq Verified | [  ] Yes [  ] No | ______________________________\nNOC(s) Obtained | [  ] Yes [  ] No | ______________________________\nPayment Terms Confirmed | [  ] Yes [  ] No | ______________________________\nCommission Agreement / Authorization | [  ] Yes [  ] No | ______________________________\nVAT Invoice Issued (if applicable) | [  ] Yes [  ] No | ______________________________\nTransfer / Registration Appointment Booked | [  ] Yes [  ] No | ______________________________\nHandover Arranged | [  ] Yes [  ] No | ______________________________\nFinal Funds Receipt Confirmed | [  ] Yes [  ] No | ______________________________\n\n3. Closing Confirmation\nThe parties confirm that all prerequisites have been met and that the transaction may be closed in accordance with applicable laws and authority requirements.\n\n4. Governing Law\nThis checklist is governed by the laws of the United Arab Emirates and applicable regulations in the Emirate of Abu Dhabi.\n\nSignatures\n\nTransaction Manager (MiCasa Real Estate LLC)\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompliance Review\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompany Stamp\n[Stamp Here]', now(), now()),

('11_noc_request_clearance_tracker', 'NOC Request & Clearance Tracker', 'Other', 'v1.0', 'Published', E'NOC Request & Clearance Tracker\n\nPurpose\nThis tracker records all NOC and authority clearance requests required for a transaction and provides an audit trail of submission, approvals, and conditions.\n\n1. Transaction Details\nDeal Reference: __________________________________________\nProperty Address: _______________________________________\nTransaction Type: [  ] Sale  [  ] Lease\nParties: ________________________________________________\nBroker Representative: __________________________________\n\n2. NOC and Clearance Log\nAuthority / Entity | Request Type | Submission Date | Status | Approval Date | Conditions / Notes\n--- | --- | --- | --- | --- | ---\n__________________ | ____________ | ______________ | ______ | _____________ | __________________________\n__________________ | ____________ | ______________ | ______ | _____________ | __________________________\n__________________ | ____________ | ______________ | ______ | _____________ | __________________________\n__________________ | ____________ | ______________ | ______ | _____________ | __________________________\n\n3. Required Documents Checklist\nThe following documents have been submitted as required:\n- Title deed / ownership proof\n- Emirates ID / Passport (parties)\n- Power of attorney (if applicable)\n- Service charge clearance (if applicable)\n- Any authority-specific forms\n\n4. Final Clearance Confirmation\nAll required NOCs and clearances have been obtained and are valid for transaction completion.\n\n5. Governing Law\nThis tracker is governed by the laws of the United Arab Emirates and applicable regulations in the Emirate of Abu Dhabi.\n\nSignatures\n\nTransaction Manager (MiCasa Real Estate LLC)\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompliance Review\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompany Stamp\n[Stamp Here]', now(), now()),

('12_commission_vat_invoice', 'Commission & VAT Invoice', 'CommissionInvoice', 'v1.0', 'Published', E'Commission & VAT Invoice\n\nPurpose\nThis invoice records brokerage commission due and complies with UAE VAT requirements for tax invoices issued by MiCasa Real Estate LLC.\n\nTAX INVOICE\n\n1. Supplier (Broker)\nLegal Name: MiCasa Real Estate LLC\nTrade License No.: ______________________________\nTRN (VAT): _____________________________________\nAddress: _______________________________________\nEmail: _________________________________________\nPhone: _________________________________________\n\n2. Customer\nCustomer Name: _________________________________________\nCustomer TRN (if applicable): ___________________________\nAddress: _______________________________________________\nEmail: _________________________________________________\nPhone: _________________________________________________\n\n3. Invoice Details\nInvoice No.: ____________________________________________\nInvoice Date: ___________________________________________\nDate of Supply: ________________________________________\nDeal Reference: _________________________________________\nProperty Address: _______________________________________\nTransaction Type: [  ] Sale  [  ] Lease\n\n4. Commission and VAT\nDescription | Amount (AED)\n--- | ---\nBrokerage Commission (Taxable) | ______________________\nVAT Rate | 5%\nVAT Amount | ______________________\nTotal Amount Payable | ______________________\n\n5. Payment Terms\nPayment Due Date: _______________________________________\nPayment Method: _________________________________________\nBank Details (if applicable): ____________________________\n\n6. Notes\nThis invoice is issued for brokerage services provided in connection with the above transaction and is subject to the UAE Federal Tax Authority regulations.\n\n7. Governing Law\nThis invoice is governed by the laws of the United Arab Emirates and applicable regulations in the Emirate of Abu Dhabi.\n\nSignatures\n\nAuthorized Signatory (MiCasa Real Estate LLC)\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCustomer Acknowledgment (if required)\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompany Stamp\n[Stamp Here]', now(), now()),

('13_commission_authorization_split_sheet', 'Commission Authorization & Split Sheet', 'Other', 'v1.0', 'Published', E'Commission Authorization & Split Sheet\n\nPurpose\nThis internal form authorizes commission payout and records the approved split among participating agents or parties for audit and payroll processing.\n\n1. Deal Information\nDeal Reference: __________________________________________\nProperty Address: _______________________________________\nTransaction Type: [  ] Sale  [  ] Lease\nCompletion Date: ________________________________________\n\n2. Commission Summary\nTotal Commission (AED): _________________________________\nVAT Applicable: [  ] Yes  [  ] No\nVAT Amount (AED): _______________________________________\nNet Commission (AED): ___________________________________\n\n3. Split Details\nParticipant | Role | Split % | Amount (AED)\n--- | --- | --- | ---\n__________________ | ____________ | ______ | __________________\n__________________ | ____________ | ______ | __________________\n__________________ | ____________ | ______ | __________________\n\n4. Payment Instructions\nPayment Method: _________________________________________\nPayment Date: ___________________________________________\nBank / Wallet Details: ___________________________________\n\n5. Approvals\nThis payout is authorized in accordance with company policy and applicable regulations.\n\n6. Governing Law\nThis internal authorization is maintained in accordance with the laws of the United Arab Emirates and applicable regulations in the Emirate of Abu Dhabi.\n\nSignatures\n\nPrepared By\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nApproved By\nName: __________________________________________\nSignature: ______________________________________\nDate: __________________________________________\n\nCompany Stamp\n[Stamp Here]', now(), now()),

